ENTRY.C_REF_NUMBER:
var type;  
 var cash=DV.getFieldValue('CHG_CASH_IND');  
 if (cash.equals('Yes')){     
 type ='BANK';   
 }else{     
 type ='CUSTOMER';   
 }   
 DV.appendField(type);

ENTRY.C_VCH_SPECIAL1:
var dest=DV.getFieldValue("CHG_FLD_ALL_CHARGE_FOR");
 var acc=DV.getFieldValue('CHG_FLD_LOCAL_CUST_AC_NO'); 
 if((dest != null && dest.equals('F')) || acc.equals("")){    DV.appendField('');  
 }else{   
  var cash=DV.getFieldValue('CHG_CASH_IND');    
 if (cash.equals('No')){      
  var sql="C_AC_NUMBER='" + acc + "'";      DV.SYS_getTableData('C_AC_TITLE','eximsys.std_ac_number',sql); 
    }else{      var title ='SETTLEMENT SUSPENSE';      
 DV.appendField(title);   
  }  }

ENTRY.N_AMT:
var ex=DV.getCurrentDoData('CHG_TEMP1'); 
var amt=DV.toFloat(DV.getCurrentDoData('CHG_COLLECT_AMT')); 
var vatamt=DV.toFloat(DV.getCurrentDoData('CHG_LOCAL_COLLECT_VAT_AMT'));
DV.writeLog("vatamt is "+vatamt); 
if(ex != null){ 
     if (ex.equals('exclude')) {
	amt='0';  
	vatamt = '0';
     }      
}
if(vatamt>0){
	var net=amt+vatamt;
	DV.writeLog("net"+net);
	DV.appendField(net);
}else{
	DV.appendField(amt);   
}

